func PathParamsBinder(c Context) *ValueBinder {
	return &ValueBinder{
		failFast:	true,
		ValueFunc:	c.Param,
		ValuesFunc: func(sourceParam string) []string {

			value := c.Param(sourceParam)
			if value == "" {
				return nil
			}
			return []string{value}
		},
		ErrorFunc:	NewBindingError,
	}
}
